import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Fabric と Modding への入門","description":"Fabric と Minecraft: Java 版での Modding に関するイントロダクション。","frontmatter":{"title":"Fabric と Modding への入門","description":"Fabric と Minecraft: Java 版での Modding に関するイントロダクション。","authors":["IMB11","itsmiir"],"authors-nogithub":["basil4088"],"files":[]},"headers":[],"relativePath":"ja_jp/1.21.4/develop/getting-started/introduction-to-fabric-and-modding.md","filePath":"versions/1.21.4/translated/ja_jp/develop/getting-started/introduction-to-fabric-and-modding.md","lastUpdated":1760721669000}`);var a={name:`ja_jp/1.21.4/develop/getting-started/introduction-to-fabric-and-modding.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Fabric と Modding への入門 <a class="header-anchor" href="#h1" aria-label="Permalink to “Fabric と Modding への入門”">​</a></h1><h2 id="prerequisites" tabindex="-1">前提条件 <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “前提条件”">​</a></h2><p>Fabric と Minecraft の Modding を始めるには、Java の基礎文法と、オブジェクト指向プログラミング（OOP）の理解が必要です。</p><p>これらの知識がない方は、Java と OOP に関する以下のチュートリアルをご覧いただけます。</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Learn Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Introduction to OOP</a></li></ul><h3 id="terminology" tabindex="-1">用語集 <a class="header-anchor" href="#terminology" aria-label="Permalink to “用語集”">​</a></h3><p>始める前に、Fabric における Modding で使われる用語について説明します:</p><ul><li><strong>Mod</strong>: 新しい機能の追加や既存の機能の変更といった、ゲームに加える変更。</li><li><strong>Mod ローダー</strong>: Fabric Loader のような、Mod をゲームに読み込ませるツール。</li><li><strong>Mixin</strong>: 実行時にゲームのプログラムを変更するツール。詳細は <a href="https://fabricmc.net/wiki/ja:tutorial:mixin_introduction" target="_blank" rel="noreferrer">Mixin の概要</a> を参照してください。</li><li><strong>Gradle</strong>: Mod のビルドとコンパイルを自動化するツール。Fabric では Mod のビルドに使用している。</li><li><strong>マッピング（Mappings）</strong>: 難読化されたコードと人間が読めるコードの間における対応。</li><li><strong>難読化（Obfuscation）</strong>: プログラムを読みづらくする処理。Mojang が Minecraft のプログラムを守るために行う。</li><li><strong>再マッピング</strong>: 難読化されたプログラムを人間が読めるプログラムに変更する処理。</li></ul><h2 id="what-is-fabric" tabindex="-1">Fabric とは <a class="header-anchor" href="#what-is-fabric" aria-label="Permalink to “Fabric とは”">​</a></h2><p>Fabric は Minecraft: Java 版向けの軽量な Modding ツール郡です。</p><p>Fabric はシンプルで扱いやすい Modding プラットフォームを目指して設計されています。 開発はコミュニティによって行われており、オープンソースです。つまり、誰でもプロジェクトに貢献することができます。</p><p>Fabric には 4 つの主要なコンポーネントがあります:</p><ul><li><strong>Fabric Loader</strong>: Minecraft やその他のゲームやアプリケーション向けに設計された、柔軟でプラットフォームに依存しない Mod ローダー。</li><li><strong>Fabric Loom</strong>: Mod の開発とデバッグを簡単にする Gradle プラグイン。</li><li><strong>Fabric API</strong>: Mod の開発に使用する API とツールのセット。</li><li><strong>Yarn</strong>: オープンな Minecraft のマッピング。Creative Commons Zero ライセンスのもと、誰でも自由に使うことができる。</li></ul><h2 id="why-is-fabric-necessary-to-mod-minecraft" tabindex="-1">Fabric が Minecraft の Modding に必要である理由 <a class="header-anchor" href="#why-is-fabric-necessary-to-mod-minecraft" aria-label="Permalink to “Fabric が Minecraft の Modding に必要である理由”">​</a></h2><blockquote><p>Modding とは、挙動を変更したり、新しい機能を追加したりするためにゲームを改造することです。Minecraft の場合、新しいアイテム、ブロック、エンティティの追加から、ゲームの仕様の変更、新しいゲームモードの追加まで、あらゆることが含まれます。</p></blockquote><p>Minecraft: Java 版は Mojang によって難読化されており、単独での Modding は困難です。 しかし、Fabric のような Modding ツールを使うことで、簡単に変更を加えることができます。 ツールの中には、Modding を支援するいくつかのマッピングが存在します。</p><p>Loom はマッピングを用いて、難読化されたプログラムを人間が読める形式に再マッピングします。これにより、Mod 開発者が簡単にゲームのプログラムを理解し、変更を加えることができるようになります。 Yarn は人気で非常に優れたマッピングですが、別のマッピングも使用できます。 マッピングにはそれぞれ独自の強みや目的があります。</p><p>Loom を用いることで、再マッピングされたコードに対する Mod の開発・コンパイルを容易に行え、 Fabric Loader はこれらの Mod をゲームに読み込むことを可能にします。</p><h2 id="what-does-fabric-api-provide-and-why-is-it-needed" tabindex="-1">Fabric API が提供するものと、必要である理由 <a class="header-anchor" href="#what-does-fabric-api-provide-and-why-is-it-needed" aria-label="Permalink to “Fabric API が提供するものと、必要である理由”">​</a></h2><blockquote><p>Fabric API は Modding をする際に使用する API とツールのセットです。</p></blockquote><p>Fabric API は Minecraft の既存の機能に対する様々な API を提供します。例えば、新しいフックやイベントを提供したり、Modding を簡単にするユーティリティやツール（推移的アクセスワイドナーや、内部レジストリへのアクセス機能など）を提供したりします。</p><p>Fabric API は強力な機能を提供しますが、ブロックの登録を含む一部の基本的なタスクはバニラの API を通じて行うことができます。</p>`,22)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};